// Get the output directly from the "Extract Lead State" node
const data = $node["Extract Lead State"].json;

return {
  ...data,
  score: data.budget > 10000 ? 80 : 30,
  isHot: data.budget > 10000
};

// Extract JSON data from AI output
const rawOutput = $node["Qualify Lead Conversationally"].json.output || "";
let state = { name: "unknown", industry: "unknown", budget: 0, isReady: false };
try {
  const jsonMatch = rawOutput.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    let jsonString = jsonMatch[0].replace(/'/g, '"');
    const newData = JSON.parse(jsonString);
    state.name = newData.name || "unknown";
    state.industry = newData.industry || "unknown";
    state.budget = Number(newData.budget) || 0;
  }
} catch (e) {}
if (state.name !== "unknown" && state.industry !== "unknown" && state.budget > 0) state.isReady = true;
return state;
